function deprecated(fn, msg) {
  var warned = false;

  function deprecatedFn() {
    if (!warned) {
      if (typeof console !== 'undefined' && typeof console.warn === 'function') {
        console.warn('DeprecationWarning: ' + msg);
      }
      warned = true;
    }
    return fn.apply(this, arguments);
  }

  return deprecatedFn;
}

module.exports = deprecated;
